{
  "ticket_id": "SCRUM-9",
  "plan_version": 1,
  "units": [
    {
      "id": "unit-1",
      "description": "Create Todo types, in-memory store, and validation logic with unit tests. Define the Todo interface (id, title, description, status, createdAt, updatedAt, dueDate). Implement an in-memory store module with CRUD operations (getAll with optional status filter, getById, create, update, delete). Implement validation functions for create and update inputs (title required and max 200 chars, dueDate must be in future, status must be pending/completed). Include unit tests for all validation rules and store operations.",
      "affected_files": [
        "src/lib/todos/types.ts",
        "src/lib/todos/store.ts",
        "src/lib/todos/validation.ts",
        "src/__tests__/todos-validation.test.ts",
        "src/__tests__/todos-store.test.ts"
      ],
      "dependencies": [],
      "complexity": "moderate",
      "test_criteria": [
        {
          "scenario": "create_todo_validates_title_length",
          "test_type": "unit",
          "description": "Validation logic rejects titles longer than 200 characters"
        },
        {
          "scenario": "create_todo_validates_future_due_date",
          "test_type": "unit",
          "description": "Validation logic rejects past due dates"
        },
        {
          "scenario": "store_getAll_returns_empty_array",
          "test_type": "unit",
          "description": "Store returns empty array when no todos exist"
        },
        {
          "scenario": "store_getAll_filters_by_status",
          "test_type": "unit",
          "description": "Store filters todos by status when filter parameter provided"
        },
        {
          "scenario": "store_create_generates_uuid_and_timestamps",
          "test_type": "unit",
          "description": "Store create assigns uuid, createdAt, updatedAt, and default status pending"
        },
        {
          "scenario": "store_update_returns_null_for_missing_id",
          "test_type": "unit",
          "description": "Store update returns null when todo ID does not exist"
        },
        {
          "scenario": "store_delete_returns_false_for_missing_id",
          "test_type": "unit",
          "description": "Store delete returns false when todo ID does not exist"
        },
        {
          "scenario": "validation_rejects_empty_string_title",
          "test_type": "unit",
          "description": "Validation rejects empty string and whitespace-only titles"
        },
        {
          "scenario": "validation_rejects_invalid_status",
          "test_type": "unit",
          "description": "Validation rejects status values other than pending/completed"
        },
        {
          "scenario": "validation_rejects_invalid_date_format",
          "test_type": "unit",
          "description": "Validation rejects invalid date format strings for dueDate"
        }
      ]
    },
    {
      "id": "unit-2",
      "description": "Implement GET /api/todos and POST /api/todos route handlers with integration tests. GET supports ?status=completed|pending filter, returns 400 for invalid status values, returns all todos sorted by createdAt descending. POST validates input using validation module, returns 201 with created todo, returns 400 with descriptive errors for invalid input. All responses use consistent JSON format with proper Content-Type headers.",
      "affected_files": [
        "src/app/api/todos/route.ts",
        "src/__tests__/todos-collection-api.test.ts"
      ],
      "dependencies": ["unit-1"],
      "complexity": "moderate",
      "test_criteria": [
        {
          "scenario": "list_all_todos_empty_state",
          "test_type": "integration",
          "description": "GET /api/todos returns empty array when no todos exist"
        },
        {
          "scenario": "list_todos_with_status_filter",
          "test_type": "integration",
          "description": "GET /api/todos?status=completed filters results correctly"
        },
        {
          "scenario": "invalid_status_filter_returns_400",
          "test_type": "integration",
          "description": "GET /api/todos?status=invalid returns HTTP 400 with descriptive error"
        },
        {
          "scenario": "create_todo_validates_required_title",
          "test_type": "integration",
          "description": "POST /api/todos without title field returns HTTP 400"
        },
        {
          "scenario": "create_todo_success_response",
          "test_type": "integration",
          "description": "POST /api/todos with valid data returns 201 with complete todo object"
        },
        {
          "scenario": "consistent_error_format",
          "test_type": "integration",
          "description": "All validation errors from GET and POST follow the same JSON error structure"
        }
      ]
    },
    {
      "id": "unit-3",
      "description": "Implement PATCH /api/todos/:id and DELETE /api/todos/:id route
